#include <stdio.h>

int linearSearch(int arr[], int n, int target) {
    for (int i = 0; i < n; i++) {
        if (arr[i] == target) {
            return i;
        }
    }
    return -1;
}

int binarySearch(int arr[], int n, int target) {
    int left = 0, right = n - 1;

    while (left <= right) {
        int mid = (left + right) / 2;

        if (arr[mid] == target) {
            return mid;
        } else if (arr[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return -1;
}

int main() {
    int numbers[] = {4, 12, 7, 23, 9, 1, 18};
    int n = 7;
    int target = 23;

    int linearResult = linearSearch(numbers, n, target);
    printf("Dogrusal arama: %d indeks %d'de bulundu\n", target, linearResult);

    // Binary arama icin sirali dizi
    int sortedNumbers[] = {1, 4, 7, 9, 12, 18, 23};
    int binaryResult = binarySearch(sortedNumbers, n, target);
    printf("Binary arama: %d indeks %d'de bulundu\n", target, binaryResult);

    int notFound = linearSearch(numbers, n, 99);
    printf("\n99 araniyor (bulunamayacak): %d\n", notFound);

    return 0;
}
